function half_day_leave_table_insert(&$error_message = '') {
	global $Translation;

	// mm: can member insert record?
	$arrPerm = getTablePermissions('half_day_leave_table');
	if(!$arrPerm['insert']) {
		$error_message = $Translation['no insert permission'];
		return false;
	}

	$data = [
		'approval_from' => Request::val('approval_from', 'CEO'),
		'leave_type' => Request::val('leave_type', 'Morning - Afternoon Shift (1st Half)'),
		'purpose_of_leave' => br2nl(Request::val('purpose_of_leave', '')),
		'date' => Request::dateComponents('date', '1'),
		'approval_status' => Request::val('approval_status', 'Under Consideration'),
		'approval_remarks' => Request::val('approval_remarks', ''),
		'created_at' => parseCode('<%%creationDateTime%%>', true),
		'created_by' => parseCode('<%%creatorUsername%%>', true),
	];

	// record owner is current user
	$recordOwner = getLoggedMemberID();

	$recID = tableInsert('half_day_leave_table', $data, $recordOwner, $error_message);

	// if this record is a copy of another record, copy children if applicable
	if(strlen(Request::val('SelectedID')) && $recID !== false)
		half_day_leave_table_copy_children($recID, Request::val('SelectedID'));

	return $recID;
}

function half_day_leave_table_copy_children($destination_id, $source_id) {
	global $Translation;
	$requests = []; // array of curl handlers for launching insert requests
	$eo = ['silentErrors' => true];
	$safe_sid = makeSafe($source_id);
	$currentUsername = getLoggedMemberID();
	$errorMessage = '';

	// launch requests, asynchronously
	curl_batch($requests);
}

function half_day_leave_table_delete($selected_id, $AllowDeleteOfParents = false, $skipChecks = false) {
	// insure referential integrity ...
	global $Translation;
	$selected_id = makeSafe($selected_id);

	// mm: can member delete record?
	if(!check_record_permission('half_day_leave_table', $selected_id, 'delete')) {
		return $Translation['You don\'t have enough permissions to delete this record'];
	}

	// hook: half_day_leave_table_before_delete
	if(function_exists('half_day_leave_table_before_delete')) {
		$args = [];
		if(!half_day_leave_table_before_delete($selected_id, $skipChecks, getMemberInfo(), $args))
			return $Translation['Couldn\'t delete this record'] . (
				!empty($args['error_message']) ?
					'<div class="text-bold">' . strip_tags($args['error_message']) . '</div>'
					: ''
			);
	}

	sql("DELETE FROM `half_day_leave_table` WHERE `id`='{$selected_id}'", $eo);

	// hook: half_day_leave_table_after_delete
	if(function_exists('half_day_leave_table_after_delete')) {
		$args = [];
		half_day_leave_table_after_delete($selected_id, getMemberInfo(), $args);
	}

	// mm: delete ownership data
	sql("DELETE FROM `membership_userrecords` WHERE `tableName`='half_day_leave_table' AND `pkValue`='{$selected_id}'", $eo);
}

function half_day_leave_table_update(&$selected_id, &$error_message = '') {
	global $Translation;

	// mm: can member edit record?
	if(!check_record_permission('half_day_leave_table', $selected_id, 'edit')) return false;

	$data = [
		'approval_from' => Request::val('approval_from', ''),
		'leave_type' => Request::val('leave_type', ''),
		'purpose_of_leave' => br2nl(Request::val('purpose_of_leave', '')),
		'date' => Request::dateComponents('date', ''),
		'approval_status' => Request::val('approval_status', ''),
		'approval_remarks' => Request::val('approval_remarks', ''),
		'last_updated_at' => parseCode('<%%editingDateTime%%>', false),
		'last_updated_by' => parseCode('<%%editorUsername%%>', false),
	];

	if($data['leave_type'] === '') {
		echo StyleSheet() . "\n\n<div class=\"alert alert-danger\">{$Translation['error:']} 'Leave Type': {$Translation['field not null']}<br><br>";
		echo '<a href="" onclick="history.go(-1); return false;">' . $Translation['< back'] . '</a></div>';
		exit;
	}
	if($data['purpose_of_leave'] === '') {
		echo StyleSheet() . "\n\n<div class=\"alert alert-danger\">{$Translation['error:']} 'Purpose of Leave': {$Translation['field not null']}<br><br>";
		echo '<a href="" onclick="history.go(-1); return false;">' . $Translation['< back'] . '</a></div>';
		exit;
	}
	if($data['date'] === '') {
		echo StyleSheet() . "\n\n<div class=\"alert alert-danger\">{$Translation['error:']} 'Date': {$Translation['field not null']}<br><br>";
		echo '<a href="" onclick="history.go(-1); return false;">' . $Translation['< back'] . '</a></div>';
		exit;
	}
	// get existing values
	$old_data = getRecord('half_day_leave_table', $selected_id);
	if(is_array($old_data)) {
		$old_data = array_map('makeSafe', $old_data);
		$old_data['selectedID'] = makeSafe($selected_id);
	}

	$data['selectedID'] = makeSafe($selected_id);

	// hook: half_day_leave_table_before_update
	if(function_exists('half_day_leave_table_before_update')) {
		$args = ['old_data' => $old_data];
		if(!half_day_leave_table_before_update($data, getMemberInfo(), $args)) {
			if(isset($args['error_message'])) $error_message = $args['error_message'];
			return false;
		}
	}

	$set = $data; unset($set['selectedID']);
	foreach ($set as $field => $value) {
		$set[$field] = ($value !== '' && $value !== NULL) ? $value : NULL;
	}

	if(!update(
		'half_day_leave_table',
		backtick_keys_once($set),
		['`id`' => $selected_id],
		$error_message
	)) {
		echo $error_message;
		echo '<a href="half_day_leave_table_view.php?SelectedID=' . urlencode($selected_id) . "\">{$Translation['< back']}</a>";
		exit;
	}


	update_calc_fields('half_day_leave_table', $data['selectedID'], calculated_fields()['half_day_leave_table']);

	// hook: half_day_leave_table_after_update
	if(function_exists('half_day_leave_table_after_update')) {
		if($row = getRecord('half_day_leave_table', $data['selectedID'])) $data = array_map('makeSafe', $row);

		$data['selectedID'] = $data['id'];
		$args = ['old_data' => $old_data];
		if(!half_day_leave_table_after_update($data, getMemberInfo(), $args)) return;
	}

	// mm: update record update timestamp
	set_record_owner('half_day_leave_table', $selected_id);
}

