		$templateCode = str_replace('<%%URLVALUE(purpose_of_leave)%%>', urlencode($urow['purpose_of_leave']), $templateCode);
		$templateCode = str_replace('<%%VALUE(date)%%>', app_datetime($row['date']), $templateCode);
